import React from 'react';
import { AppstoreOutlined, MailOutlined, SettingOutlined } from '@ant-design/icons';
import { Menu } from 'antd';

const { SubMenu } = Menu;

const MenuItems = () => {
  return (
    <Menu mode="vertical">
      <SubMenu key="sub1" icon={<MailOutlined />} title="Navigation One">
        <Menu.Item key="1"><a href="/option1">Option 1</a></Menu.Item>
        <Menu.Item key="2"><a href="/option2">Option 2</a></Menu.Item>
      </SubMenu>

      <SubMenu key="sub2" icon={<AppstoreOutlined />} title="Navigation Two">
        <Menu.Item key="5"><a href="/option5">Option 5</a></Menu.Item>
        <Menu.Item key="6"><a href="/option6">Option 6</a></Menu.Item>
        <SubMenu key="sub3" title="Submenu">
          <Menu.Item key="7"><a href="/option7">Option 7</a></Menu.Item>
        </SubMenu>
      </SubMenu>

      <SubMenu key="sub4" icon={<SettingOutlined />} title="Navigation Three">
        <Menu.Item key="9"><a href="/option9">Option 9</a></Menu.Item>
        <Menu.Item key="10"><a href="/option10">Option 10</a></Menu.Item>
        <Menu.Item key="11"><a href="/option11">Option 11</a></Menu.Item>
        <Menu.Item key="12"><a href="/option12">Option 12</a></Menu.Item>
      </SubMenu>
    </Menu>
  );
};

export default MenuItems;
